<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Sticky Header</title>
  <style>
    body { margin: 0; font-family: system-ui, sans-serif; }
    header {
      position: sticky;   /* CSS sticky */
      top: 0;
      z-index: 1000;
      background: white;
      border-bottom: 1px solid #e5e7eb;
      transition: box-shadow .2s ease, background .2s ease;
      padding: 16px 20px;
    }
    header.is-stuck {      /* toggled by JS when scrolled */
      box-shadow: 0 8px 24px rgba(0,0,0,.12);
      background: rgba(255,255,255,.95);
      backdrop-filter: blur(8px);
    }
    main { padding: 24px 20px; }
    .spacer { height: 200vh; } /* demo scroll */
  </style>
</head>
<body>
  <header id="siteHeader">
    <strong>My Site</strong>
  </header>

  <main>
    <p>Scroll down to see the header "stick" and gain a shadow.</p>
    <div class="spacer"></div>
  </main>

  <script>
    // Add a class when the page has been scrolled (for styling like shadow)
    const header = document.getElementById('siteHeader');

    const onScroll = () => {
      header.classList.toggle('is-stuck', window.scrollY > 0);
    };

    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll(); // initialize on load
  </script>
</body>
</html>
